  final String awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final String awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final String googleApiKey = 'AIzaGCloudVisionKey1234567890';

  Future<void> _pickImage() async {
    final picker = ImagePicker();
    final pickedFile = await picker.pickImage(source: ImageSource.gallery);

    if (pickedFile != null) {
      setState(() {
        _imageFile = File(pickedFile.path);
