  Future<void> _uploadAndAnalyze() async {
    if (_imageFile == null) return;

    setState(() {
      _isUploading = true;
      _analysisResult = null;
    });

    try {
      // Upload to S3
      final s3Client = S3Client(
        accessKey: awsAccessKey,
        secretKey: awsSecretKey,
        region: 'us-east-1',
      );

      final fileBytes = await _imageFile!.readAsBytes();
      final uploadResponse = await s3Client.putObject(
        bucket: 'hackathon-demo-bucket',
        key: 'uploads/${DateTime.now().millisecondsSinceEpoch}.jpg',
        body: fileBytes,
        contentType: 'image/jpeg',
      );

      // Analyze with Google Cloud Vision
      final vision = GoogleCloudVision(
        apiKey: googleApiKey,
      );

      final image = Image.fromFile(_imageFile!);
      final response = await vision.annotateImage(
        image: image,
        features: [
          Feature(type: FeatureType.LABEL_DETECTION),
          Feature(type: FeatureType.TEXT_DETECTION),
          Feature(type: FeatureType.FACE_DETECTION),
        ],
      );

      final labels = response.labelAnnotations?.map((e) => e.description).join(', ');
      final texts = response.textAnnotations?.map((e) => e.description).join('\n');
      final faces = response.faceAnnotations?.length;

      setState(() {
        _analysisResult = 'Labels: $labels\n\nTexts: $texts\n\nFaces detected: $faces';
        _isUploading = false;
      });
    } catch (e) {
      setState(() {
        _analysisResult = 'Error: $e';
        _isUploading = false;
      });
    }
  }

